mapper.select:
SELECT name 
FROM tbl_dining 
WHERE dining_id = #{dining_id}

mapper.update:
UPDATE dining_reservations
SET status = #{status}
WHERE dining_reservation_id = #{resId}

mapper.select:
SELECT COUNT(*)
FROM dining_tables t
WHERE t.FK_DINING_ID = #{diningId}
  AND t.ACTIVE_YN = 'Y'
  AND t.MAX_CAPACITY >= #{totalGuests}
  AND NOT EXISTS (
      SELECT 1 FROM tbl_dining_block b
      WHERE b.FK_DINING_ID = t.FK_DINING_ID
        AND b.BLOCK_DATE = #{resDate}
        AND (b.BLOCK_TIME = #{resTime} OR b.BLOCK_TIME = 'ALL')
  )
  AND NOT EXISTS (
      SELECT 1 FROM dining_reservations r
      WHERE r.TABLE_ID = t.TABLE_ID
        AND r.RES_DATE = #{resDate}
        AND r.RES_TIME = #{resTime}
        AND r.STATUS != 'CANCELED'
  )

mapper.insert:
INSERT INTO tbl_dining_block (
    BLOCK_ID, FK_DINING_ID, BLOCK_DATE, BLOCK_TIME, REASON
) VALUES (
    SEQ_BLOCK_ID.NEXTVAL, #{fkDiningId}, #{blockDate}, #{blockTime}, #{reason}
)

mapper.select:
SELECT COUNT(*)
FROM tbl_dining_block
WHERE FK_DINING_ID = #{diningId}
  AND BLOCK_DATE = #{resDate}
  AND (
      BLOCK_TIME = 'ALL'           
      OR BLOCK_TIME = #{resTime}  
  )
